### Which @angular/* package(s) are the source of the bug?

compiler

### Is this a regression?

No

### Description

Consider this example:

```ts
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

@sealed
class BugReport {
  type: string|number = "report";
  title: string;

  constructor(t: string) {
    this.title = t;
  }
}

class BugReportChild extends BugReport {
  declare type: number;
}

@Directive({})
export class Base {
  prop: string|number = 'report';
}

@Directive({
  selector: '[appCell]'
})
export class Child extends Base {
  declare prop: number;
  constructor() {
    super();
    console.log(this.prop)
    let br = new BugReportChild('title');
    console.log(br.type)
  }

}
```

The expected behaviour is both `console.log(this.prop)` and `console.log(br.type)` print 'report' in the console.

But that is not the case. properties that have a `declare` in the child class directive are set to `undefined`.

